import{M as e,d as t,h as n}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as r}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var i=JSON.parse(`{"title":"Preview Options","description":"","frontmatter":{},"headers":[],"relativePath":"config/preview-options.md","filePath":"config/preview-options.md"}`),a={name:`config/preview-options.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /config\\preview-options.md for this page in Markdown format</div><h1 id="preview-options" tabindex="-1">Preview Options <a class="header-anchor" href="#preview-options" aria-label="Permalink to “Preview Options”">​</a></h1><p>Unless noted, the options in this section are only applied to preview.</p><h2 id="preview-host" tabindex="-1">preview.host <a class="header-anchor" href="#preview-host" aria-label="Permalink to “preview.host”">​</a></h2><ul><li><strong>Type:</strong> <code>string | boolean</code></li><li><strong>Default:</strong> <a href="./server-options#server-host"><code>server.host</code></a></li></ul><p>Specify which IP addresses the server should listen on. Set this to <code>0.0.0.0</code> or <code>true</code> to listen on all addresses, including LAN and public addresses.</p><p>This can be set via the CLI using <code>--host 0.0.0.0</code> or <code>--host</code>.</p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>There are cases when other servers might respond instead of Vite. See <a href="./server-options#server-host"><code>server.host</code></a> for more details.</p></div><h2 id="preview-allowedhosts" tabindex="-1">preview.allowedHosts <a class="header-anchor" href="#preview-allowedhosts" aria-label="Permalink to “preview.allowedHosts”">​</a></h2><ul><li><strong>Type:</strong> <code>string[] | true</code></li><li><strong>Default:</strong> <a href="./server-options#server-allowedhosts"><code>server.allowedHosts</code></a></li></ul><p>The hostnames that Vite is allowed to respond to.</p><p>See <a href="./server-options#server-allowedhosts"><code>server.allowedHosts</code></a> for more details.</p><h2 id="preview-port" tabindex="-1">preview.port <a class="header-anchor" href="#preview-port" aria-label="Permalink to “preview.port”">​</a></h2><ul><li><strong>Type:</strong> <code>number</code></li><li><strong>Default:</strong> <code>4173</code></li></ul><p>Specify server port. Note if the port is already being used, Vite will automatically try the next available port so this may not be the actual port the server ends up listening on.</p><p><strong>Example:</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defineConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  server: {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    port: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3030</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  preview: {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    port: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><h2 id="preview-strictport" tabindex="-1">preview.strictPort <a class="header-anchor" href="#preview-strictport" aria-label="Permalink to “preview.strictPort”">​</a></h2><ul><li><strong>Type:</strong> <code>boolean</code></li><li><strong>Default:</strong> <a href="./server-options#server-strictport"><code>server.strictPort</code></a></li></ul><p>Set to <code>true</code> to exit if port is already in use, instead of automatically trying the next available port.</p><h2 id="preview-https" tabindex="-1">preview.https <a class="header-anchor" href="#preview-https" aria-label="Permalink to “preview.https”">​</a></h2><ul><li><strong>Type:</strong> <code>https.ServerOptions</code></li><li><strong>Default:</strong> <a href="./server-options#server-https"><code>server.https</code></a></li></ul><p>Enable TLS + HTTP/2.</p><p>See <a href="./server-options#server-https"><code>server.https</code></a> for more details.</p><h2 id="preview-open" tabindex="-1">preview.open <a class="header-anchor" href="#preview-open" aria-label="Permalink to “preview.open”">​</a></h2><ul><li><strong>Type:</strong> <code>boolean | string</code></li><li><strong>Default:</strong> <a href="./server-options#server-open"><code>server.open</code></a></li></ul><p>Automatically open the app in the browser on server start. When the value is a string, it will be used as the URL&#39;s pathname. If you want to open the server in a specific browser you like, you can set the env <code>process.env.BROWSER</code> (e.g. <code>firefox</code>). You can also set <code>process.env.BROWSER_ARGS</code> to pass additional arguments (e.g. <code>--incognito</code>).</p><p><code>BROWSER</code> and <code>BROWSER_ARGS</code> are also special environment variables you can set in the <code>.env</code> file to configure it. See <a href="https://github.com/sindresorhus/open#app" target="_blank" rel="noreferrer">the <code>open</code> package</a> for more details.</p><h2 id="preview-proxy" tabindex="-1">preview.proxy <a class="header-anchor" href="#preview-proxy" aria-label="Permalink to “preview.proxy”">​</a></h2><ul><li><strong>Type:</strong> <code>Record&lt;string, string | ProxyOptions&gt;</code></li><li><strong>Default:</strong> <a href="./server-options#server-proxy"><code>server.proxy</code></a></li></ul><p>Configure custom proxy rules for the preview server. Expects an object of <code>{ key: options }</code> pairs. If the key starts with <code>^</code>, it will be interpreted as a <code>RegExp</code>. The <code>configure</code> option can be used to access the proxy instance.</p><p>Uses <a href="https://github.com/sagemathinc/http-proxy-3" target="_blank" rel="noreferrer"><code>http-proxy-3</code></a>. Full options <a href="https://github.com/sagemathinc/http-proxy-3#options" target="_blank" rel="noreferrer">here</a>.</p><h2 id="preview-cors" tabindex="-1">preview.cors <a class="header-anchor" href="#preview-cors" aria-label="Permalink to “preview.cors”">​</a></h2><ul><li><strong>Type:</strong> <code>boolean | CorsOptions</code></li><li><strong>Default:</strong> <a href="./server-options#server-cors"><code>server.cors</code></a></li></ul><p>Configure CORS for the preview server.</p><p>See <a href="./server-options#server-cors"><code>server.cors</code></a> for more details.</p><h2 id="preview-headers" tabindex="-1">preview.headers <a class="header-anchor" href="#preview-headers" aria-label="Permalink to “preview.headers”">​</a></h2><ul><li><strong>Type:</strong> <code>OutgoingHttpHeaders</code></li></ul><p>Specify server response headers.</p>`,39)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};